mapper.select:
SELECT p.postId, p.boardId, p.parentPostId, p.depth, p.title, p.category, p.tags, p.isPinned, p.isSecret, p.isAnonymous, p.viewCount, p.likeCount, p.commentCount, p.attachCount, p.targetDeptId, p.useYn, p.createdUser, p.createdDate, p.updateUser, p.updatedDate, m.boardName, CASE WHEN l.likeId IS NOT NULL THEN 'Y' ELSE 'N' END AS isLiked FROM board_post p LEFT JOIN board_master m ON p.boardId = m.boardId LEFT JOIN board_like l ON l.targetType = 'POST' AND l.targetId = p.postId AND l.createdUser = #{currentUser}
AND p.boardId = #{boardId}
AND p.title LIKE CONCAT('%', #{title}, '%')
AND p.category = #{category}
AND p.useYn = #{useYn}
ORDER BY p.isPinned DESC, p.createdDate DESC

SELECT p.postId, p.boardId, p.title, p.likeCount, p.viewCount, p.commentCount, m.boardName FROM board_post p LEFT JOIN board_master m ON p.boardId = m.boardId WHERE p.useYn = 'Y'
AND p.boardId = #{boardId}
ORDER BY p.likeCount DESC LIMIT #{limit}
